import React, { useContext } from 'react';
import PlanetsContext from '../context/PlanetsContext';

function Table() {
  const { store: {
    data,
    filterByName,
    filterByNumericValues,
  } } = useContext(PlanetsContext);
  const tableTemp = [
    'Name',
    'Rotation Period',
    'Orbital Period',
    'Diameter',
    'Climate',
    'Gravity',
    'Terrain',
    'Surface Water',
    'Population',
    'Films',
    'Created',
    'Edited',
    'URL',
  ];

  const renderData = filterByNumericValues || data;

  return (
    <table>
      <thead>
        <tr role="row">
          {tableTemp.map((head, index) => (
            <th key={ index }>
              {head}
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {renderData.filter((element) => element.name.includes(filterByName.name))
          .map((planet) => (
            <tr key={ planet.name }>
              <td>{planet.name}</td>
              <td>{planet.rotation_period}</td>
              <td>{planet.orbital_period}</td>
              <td>{planet.diameter}</td>
              <td>{planet.climate}</td>
              <td>{planet.gravity}</td>
              <td>{planet.terrain}</td>
              <td>{planet.surface_water}</td>
              <td>{planet.population}</td>
              <td>
                <ul>
                  {planet.films.map((film) => (
                    <li key={ film }>{film}</li>
                  ))}
                </ul>
              </td>
              <td>{planet.created}</td>
              <td>{planet.edited}</td>
              <td>
                <a href={ planet.url }>{planet.url}</a>
              </td>
            </tr>
          ))}
      </tbody>
    </table>
  );
}

export default Table;
